package com.mohit.ecommerce.controller;
import com.mohit.ecommerce.dto.*; import com.mohit.ecommerce.service.CartService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/cart") public class CartController{private final CartService s;public CartController(CartService s){this.s=s;}@GetMapping CartResponse get(Authentication a){return s.get(a.getName());}@PostMapping("/items") CartResponse add(Authentication a,@Valid @RequestBody CartItemRequest r){return s.add(a.getName(),r);}@PutMapping("/items/{productId}") CartResponse update(Authentication a,@PathVariable Long productId,@RequestParam Integer quantity){return s.update(a.getName(),productId,quantity);}@DeleteMapping("/items/{productId}") CartResponse remove(Authentication a,@PathVariable Long productId){return s.remove(a.getName(),productId);}@DeleteMapping ResponseEntity<Void> clear(Authentication a){s.clear(a.getName());return ResponseEntity.noContent().build();}}
